from fastapi import Requestfrom app.config.gfss_parameter import platform, http_ip_contextfrom app.core.logger import logdef ip_addr(request: Request) -> str:    """    Получение IP-адреса клиента в FastAPI.    """    # Unix: читаем IP из request.scope['headers'] или environ    if platform == "unix":        # В FastAPI нет environ, но есть scope        # http_ip_context — например "HTTP_X_REAL_IP"        header_name = http_ip_context.lower().replace("_", "-")        for key, value in request.headers.items():            if key.lower() == header_name:                return value        # fallback        return request.client.host    # Windows: аналог Flask request.remote_addr    return request.client.hostdef get_ip(request: Request) -> str:    return request.headers.get("X-Real-IP") or request.client.host